SELECT event_description
FROM performance_events
WHERE event_severity = 'critical';

SELECT SUM(executed) AS total_executions
FROM performance_events
WHERE event_severity = 'info';

SELECT MAX(l2_transactions) AS max_l2_transactions
FROM performance_events
WHERE event_severity = 'critical';

SELECT COUNT(*) AS event_count
FROM performance_events
WHERE event_severity = 'critical';

SELECT event_id
FROM performance_events
ORDER BY event_id;

SELECT component_name
FROM system_components
WHERE component_type = 'software';
